client_script:
frappe.web_form.on('load', function(){
  var user = (frappe.session && frappe.session.user) ? frappe.session.user : null;
  if (!user || user === 'Guest') return;

  var roles = (frappe.boot && frappe.boot.user && frappe.boot.user.roles) ? frappe.boot.user.roles : [];
  var can_select_any = roles.indexOf('Accounts Manager') !== -1 || roles.indexOf('System Manager') !== -1;

  if (!frappe.web_form.doc.date_etat) {
    frappe.web_form.set_value('date_etat', frappe.datetime.get_today());
  }

  frappe.call({
    method: 'frappe.client.get_value',
    args: {
      doctype: 'Employee',
      filters: { user_id: user, status: 'Active' },
      fieldname: ['name', 'employee_name']
    },
    callback: function(r){
      if (!r || !r.message) return;
      if (!frappe.web_form.doc.redacteur) {
        frappe.web_form.set_value('redacteur', r.message.name);
      }
      if (r.message.employee_name && !frappe.web_form.doc.redacteur_name) {
        frappe.web_form.set_value('redacteur_name', r.message.employee_name);
      }
      if (!can_select_any) {
        frappe.web_form.set_df_property('redacteur', 'read_only', 1);
      }

      setTimeout(function() {
        if (window.kyaRestructureForm) window.kyaRestructureForm();
      }, 150);
    }
  });
});
